import scala.xml._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.server.Route
import akka.http.scaladsl.model.StatusCodes
import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.stream.ActorMaterializer

object ConfigManagementService extends App {
  implicit val system = ActorSystem("ConfigManagementSystem")
  implicit val materializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  def parseXML(xmlString: String): Option[Map[String, String]] = {
    try {
      val xml = XML.loadString(xmlString)
      val settings = (xml \\ "setting").map(node => (node \@ "name", node.text)).toMap
      Some(settings)
    } catch {
      case _: Exception => None
    }
  }

  val route: Route = 
    path("parseConfig") {
      post {
        entity(as[String]) { xmlString =>
          parseXML(xmlString) match {
            case Some(settings) => complete(settings.toString)
            case None => complete(StatusCodes.BadRequest, "Invalid XML Configuration")
          }
        }
      }
    }

  Http().bindAndHandle(route, "localhost", 8080)
}